def render_tabla_imagen(headers, rows, totals_row=None, col_widths=None,
                        font_size=14, header_size=14):
    """Renderiza una tabla a imagen PNG (BytesIO) con estilo similar al PDF.
    Encabezado con fondo verde, filas alternadas, fila de totales en verde oscuro.
    Devuelve un io.BytesIO con la imagen lista para insertar en PPT."""
    n_cols = len(headers)
    n_rows = len(rows) + 1 + (1 if totals_row else 0)
    if col_widths is None:
        col_widths = [1.0] * n_cols
    total_w = sum(col_widths)
    # Tamaño del lienzo: ancho proporcional a anchos de columna, alto por cantidad de filas
    fig_w = 13.0
    row_h = 0.55  # pulgadas por fila
    fig_h = max(2.0, n_rows * row_h + 0.4)
    fig, ax = plt.subplots(figsize=(fig_w, fig_h), dpi=200)
    ax.set_xlim(0, total_w); ax.set_ylim(0, n_rows); ax.axis('off')

    GD = '#1B5E20'; GM = '#2E7D32'; GL = '#F5F5F5'
    LN = '#CFD8DC'; WH = '#FFFFFF'; GT = '#37474F'; GC_HDR = WH

    def draw_cell(x, y, w, h, text, bg, fg, bold=False, size=None):
        rect = plt.Rectangle((x, y), w, h, facecolor=bg, edgecolor=LN, linewidth=0.6)
        ax.add_patch(rect)
        ax.text(x + w/2, y + h/2, str(text),
                ha='center', va='center', color=fg,
                fontsize=size or font_size,
                fontweight='bold' if bold else 'normal',
                family='DejaVu Sans')

    # Encabezado (arriba)
    x_acc = 0
    y_top = n_rows - 1
    for ci, h in enumerate(headers):
        w = col_widths[ci]
        draw_cell(x_acc, y_top, w, 1, h, GM, GC_HDR, bold=True, size=header_size)
        x_acc += w

    # Filas
    for ri, row in enumerate(rows):
        x_acc = 0
        y = n_rows - 2 - ri
        bg = GL if ri % 2 == 0 else WH
        for ci, val in enumerate(row):
            w = col_widths[ci]
            draw_cell(x_acc, y, w, 1, val, bg, GT)
            x_acc += w

    # Fila totales
    if totals_row:
        x_acc = 0
        y = 0
        for ci, val in enumerate(totals_row):
            w = col_widths[ci]
            draw_cell(x_acc, y, w, 1, val, GD, WH, bold=True)
            x_acc += w

    plt.subplots_adjust(left=0, right=1, top=1, bottom=0)
    buf = io.BytesIO()
    plt.savefig(buf, format='png', bbox_inches='tight', pad_inches=0.05, facecolor='white')
    plt.close(fig)
    buf.seek(0)
    return buf


def gen_pptx_python(lotes, config, path):
    from pptx import Presentation
    from pptx.util import Inches, Pt, Emu
    from pptx.dml.color import RGBColor
    from pptx.enum.text import PP_ALIGN
    import base64 as _b

    VERDE_OSC = RGBColor(0x1B, 0x5E, 0x20)
    VERDE_MED = RGBColor(0x2E, 0x7D, 0x32)
    VERDE_CLA = RGBColor(0xC8, 0xE6, 0xC9)
    NARANJA   = RGBColor(0xE6, 0x51, 0x00)
    GRIS_TX   = RGBColor(0x37, 0x47, 0x4F)
    GRIS_CLR  = RGBColor(0xF5, 0xF5, 0xF5)
    BLANCO    = RGBColor(0xFF, 0xFF, 0xFF)

    prs = Presentation()
    prs.slide_width  = Inches(13.33)
    prs.slide_height = Inches(7.5)
    W = 13.33
    H = 7.5

    logo_bytes = _b.b64decode(LOGO_B64)
    unidad = config.get('unidad', 'kg/ha')

    def add_rect(slide, x, y, w, h, fill_rgb, line_rgb=None):
        from pptx.util import Inches
        shp = slide.shapes.add_shape(1, Inches(x), Inches(y), Inches(w), Inches(h))
        shp.fill.solid(); shp.fill.fore_color.rgb = fill_rgb
        if line_rgb:
            shp.line.color.rgb = line_rgb
        else:
            shp.line.fill.background()
        return shp

    def add_txt(slide, text, x, y, w, h, size=12, bold=False, color=None, align='left', italic=False):
        from pptx.util import Inches, Pt
        from pptx.enum.text import PP_ALIGN
        txb = slide.shapes.add_textbox(Inches(x), Inches(y), Inches(w), Inches(h))
        tf = txb.text_frame; tf.word_wrap = True
        p = tf.paragraphs[0]
        p.alignment = {'left':PP_ALIGN.LEFT,'center':PP_ALIGN.CENTER,'right':PP_ALIGN.RIGHT}.get(align, PP_ALIGN.LEFT)
        run = p.add_run(); run.text = str(text)
        run.font.size = Pt(size); run.font.bold = bold; run.font.italic = italic
        run.font.color.rgb = color or GRIS_TX
        return txb

    def add_header(slide, titulo, subtitulo=''):
        # Estilo "marco": linea verde gruesa abajo (en vez de caja llena),
        # acento naranja, y logo proporcional (aspect ratio del logo: 229x171 ≈ 1.339:1).
        logo_h = 0.55
        logo_w = logo_h * 1.339
        logo_buf2 = io.BytesIO(logo_bytes)
        slide.shapes.add_picture(logo_buf2, Inches(W-logo_w-0.3), Inches(0.20), Inches(logo_w), Inches(logo_h))
        # Titulo
        add_txt(slide, titulo, 0.3, 0.18, W-logo_w-0.7, 0.55,
                size=22, bold=True, color=VERDE_OSC, align='left')
        # Subtitulo (opcional)
        if subtitulo:
            add_txt(slide, subtitulo, 0.3, 0.78, W-0.6, 0.28,
                    size=10, color=GRIS_TX, italic=True, align='left')
        # Linea verde gruesa abajo + acento naranja delgado
        add_rect(slide, 0.3, 1.10, W-0.6, 0.04, VERDE_OSC)
        add_rect(slide, 0.3, 1.14, 1.5, 0.025, NARANJA)

    def add_footer(slide):
        add_txt(slide, f"Sentinel-2 L2A (Copernicus) | GNDVI=(B8-B3)/(B8+B3) | Regresion lineal | {config.get('fecha','')}",
                0.3, H-0.28, W-0.6, 0.25, size=7, color=RGBColor(0x90,0xA4,0xAE), italic=True)

    def tbl_cell(table, row, col, text, bold=False, bg=None, color=None, align='center'):
        from pptx.util import Pt
        from pptx.enum.text import PP_ALIGN
        cell = table.cell(row, col)
        cell.text = str(text)
        p = cell.text_frame.paragraphs[0]
        p.alignment = {'center':PP_ALIGN.CENTER,'left':PP_ALIGN.LEFT,'right':PP_ALIGN.RIGHT}.get(align,PP_ALIGN.CENTER)
        run = p.runs[0] if p.runs else p.add_run()
        run.font.bold = bold; run.font.size = Pt(9)
        run.font.color.rgb = color or GRIS_TX
        if bg:
            cell.fill.solid(); cell.fill.fore_color.rgb = bg

    blank_layout = prs.slide_layouts[6]

    # ── Portada con foto del cultivo ─────────────────────
    s0 = prs.slides.add_slide(blank_layout)
    # Fondo blanco por defecto
    s0.background.fill.solid(); s0.background.fill.fore_color.rgb = BLANCO

    # Buscar foto segun cultivo (matchea con prefijo: "Soja 2da" → "soja", "Maiz tardio" → "maiz")
    cultivo_raw = (config.get('cultivo','') or '').lower()
    cultivo_key = None
    for k in ['soja','maiz','trigo','cebada']:
        if cultivo_raw.startswith(k):
            cultivo_key = k; break

    foto_b64 = CARATULAS_B64.get(cultivo_key) if cultivo_key else None
    if foto_b64:
        # Foto a pantalla completa (ya recortada a 16:9 al embeber)
        foto_buf = io.BytesIO(_b.b64decode(foto_b64))
        s0.shapes.add_picture(foto_buf, Inches(0), Inches(0), Inches(W), Inches(H))
        # Banda verde sólida abajo donde va el titulo (sin gradiente para legibilidad confiable)
        banda_h = H * 0.42
        add_rect(s0, 0, H - banda_h, W, banda_h, VERDE_OSC)
        # Linea naranja delgada arriba de la banda
        add_rect(s0, 0, H - banda_h, W, 0.06, NARANJA)
    else:
        # Sin foto: fondo verde claro con borde verde oscuro abajo
        add_rect(s0, 0, 0, W, H, RGBColor(0xE8,0xF5,0xE9))
        add_rect(s0, 0, H-2.8, W, 2.8, VERDE_OSC)

    # Logo arriba a la derecha (proporcional, sin estirar — ratio 1.339:1)
    logo_buf0 = io.BytesIO(logo_bytes)
    logo_h0 = 1.0
    logo_w0 = logo_h0 * 1.339
    s0.shapes.add_picture(logo_buf0, Inches(W-logo_w0-0.3), Inches(0.4), Inches(logo_w0), Inches(logo_h0))

    # Titulo grande sobre la banda verde
    titulo = config.get('titulo','Estimacion de Rendimiento')
    # Partir titulo si tiene " — " para mejor presentacion
    partes_tit = titulo.split(' — ')
    if len(partes_tit) >= 2:
        linea1 = ' — '.join(partes_tit[:-1])
        linea2 = partes_tit[-1]
        add_txt(s0, linea1, 0.5, H-2.55, W-1.0, 0.55,
                size=22, bold=True, color=VERDE_CLA, align='center')
        add_txt(s0, linea2, 0.5, H-1.85, W-1.0, 1.0,
                size=40, bold=True, color=BLANCO, align='center')
    else:
        add_txt(s0, titulo, 0.5, H-2.0, W-1.0, 1.4,
                size=36, bold=True, color=BLANCO, align='center')

    # Acento naranja pequeño debajo del titulo
    add_rect(s0, W/2-1.0, H-0.75, 2.0, 0.06, NARANJA)

    # Linea de meta-info abajo
    add_txt(s0, f"Destino: {config.get('destino','')}  ·  Analisis {config.get('indice','GNDVI').upper()}  ·  Sentinel-2  ·  {config.get('fecha','')}",
            0.5, H-0.55, W-1.0, 0.35, size=13, color=BLANCO, align='center')

    # ── Resumen por Lote (tabla como imagen) ─────────────
    s1 = prs.slides.add_slide(blank_layout)
    add_header(s1, 'Resumen por Lote', config.get('titulo',''))

    # Calcular totales
    at = sum(l['area_ha'] for l in lotes)
    pt = sum(l['rinde_est']*l['area_ha']/1000.0 for l in lotes)
    rp_kgha = sum(l['rinde_est']*l['area_ha'] for l in lotes)/at if at else 0
    rp = convertir_rinde(rp_kgha, unidad)

    headers_resumen = ['Lote','Campo','Variedad','Sup.(ha)',f'{config.get("indice","GNDVI").upper()} prom.','R²',f'Rinde ({unidad})','Prod.(tn)']
    rows_resumen = []
    for l in lotes:
        rows_resumen.append([
            l['nombre'], l['campo'], l.get('variedad','-'),
            fmt(l['area_ha'],1), f"{l['idx_prom']:.4f}",
            f"{l['r2']:.3f}"+(' *' if l['r2']<0.5 else ''),
            fmt(convertir_rinde(l['rinde_est'],unidad),2),
            fmt(l['rinde_est']*l['area_ha']/1000.0,1),
        ])
    totals_resumen = ['TOTAL','','',fmt(at,1),'','',fmt(rp,2), fmt(pt,1)+' tn']
    col_w = [1.5,1.5,1.3,0.9,1.3,0.7,1.3,1.2]

    img_tabla = render_tabla_imagen(
        headers_resumen, rows_resumen, totals_resumen,
        col_widths=col_w, font_size=15, header_size=15)

    # Calcular tamaño manteniendo aspect ratio. La imagen sale a 13" de ancho aprox.
    # En el slide ocupa todo el ancho disponible (W-0.6) y se escala.
    tabla_w = W - 0.6
    # alto proporcional: cantidad filas + header + total
    n_rows_total = len(rows_resumen) + 1 + 1
    tabla_h = min(H - 1.5, n_rows_total * 0.45 + 0.3)

    # Centrar verticalmente debajo del header
    y_tabla = 1.4 + max(0, (H - 1.5 - tabla_h) / 2)
    s1.shapes.add_picture(img_tabla, Inches(0.3), Inches(y_tabla),
                           Inches(tabla_w), Inches(tabla_h))

    add_footer(s1)

    # ── Una slide por lote ────────────────────────────────
    for l in lotes:
        sl = prs.slides.add_slide(blank_layout)
        var_str = f" · Var: {l['variedad']}" if l.get('variedad') else ''
        add_header(sl, l['nombre'],
                   f"Campo: {l['campo']}{var_str}  ·  Cultivo: {l['cultivo']}  ·  Sup.: {fmt(l['area_ha'],1)} ha")

        # Mapa
        if l.get('mapa_buf'):
            try:
                l['mapa_buf'].seek(0)
                sl.shapes.add_picture(l['mapa_buf'], Inches(0.3), Inches(1.1), Inches(7.5), Inches(5.0))
            except: pass

        # Panel derecho - solo puntos dentro del lote (ya filtrados en procesar)
        px = 8.1

        pts = l.get('puntos_datos', [])
        if pts:
            # Tabla de puntos como imagen renderizada (no editable, mejor legibilidad)
            headers_pts = ['Ambiente', config.get('indice','GNDVI').upper(), f'Rinde ({unidad})']
            rows_pts = []
            for p in pts:
                rows_pts.append([p['amb'], f"{p['idx_val']:.4f}", fmt(convertir_rinde(p['rinde'],unidad),2)])
            col_pts = [2.0, 1.3, 1.6]
            img_pts = render_tabla_imagen(headers_pts, rows_pts, totals_row=None,
                                          col_widths=col_pts, font_size=13, header_size=13)
            # Calcular alto proporcional segun cantidad de puntos
            n_pts_rows = len(rows_pts) + 1  # filas + header
            tabla_pts_h = min(3.5, n_pts_rows * 0.4 + 0.2)
            sl.shapes.add_picture(img_pts, Inches(px), Inches(1.1),
                                   Inches(4.9), Inches(tabla_pts_h))
            y_mod = 1.1 + tabla_pts_h + 0.2
        else:
            y_mod = 1.5
        add_rect(sl, px, y_mod, 4.9, 0.3, VERDE_MED)
        add_txt(sl, 'Modelo de Correlacion', px, y_mod, 4.9, 0.3, size=9, bold=True, color=BLANCO, align='center')
        add_txt(sl, l.get('ecuacion',''), px+0.1, y_mod+0.32, 3.2, 0.28, size=8, color=GRIS_TX)
        add_txt(sl, f"R²: {l['r2']:.3f}", px+3.3, y_mod+0.32, 1.5, 0.28, size=8, color=GRIS_TX)
        add_txt(sl, f"GNDVI prom.: {l['idx_prom']:.4f}", px+0.1, y_mod+0.62, 4.7, 0.28, size=8, color=GRIS_TX)

        # Caja rendimiento
        y_rinde = H - 1.5
        add_rect(sl, px, y_rinde, 4.9, 1.3, VERDE_MED)
        add_txt(sl, 'RENDIMIENTO ESTIMADO', px, y_rinde+0.05, 4.9, 0.28,
                size=9, bold=True, color=VERDE_CLA, align='center')
        add_txt(sl, f"{fmt(convertir_rinde(l['rinde_est'],unidad),2)} {unidad}", px, y_rinde+0.32, 4.9, 0.55,
                size=26, bold=True, color=BLANCO, align='center')
        add_txt(sl, f"Produccion: {fmt(l['rinde_est']*l['area_ha']/1000.0,1)} tn  ·  Sup.: {fmt(l['area_ha'],1)} ha",
                px, y_rinde+0.9, 4.9, 0.3, size=9, color=VERDE_CLA, align='center')
        add_footer(sl)

    prs.save(path)

# HTTP
class Handler(http.server.BaseHTTPRequestHandler):
    def log_message(self,fmt,*a): pass
    def cors(self):
        self.send_header('Access-Control-Allow-Origin','*')
        self.send_header('Access-Control-Allow-Methods','POST, GET, OPTIONS')
        self.send_header('Access-Control-Allow-Headers','Content-Type')
    def do_OPTIONS(self): self.send_response(200); self.cors(); self.end_headers()
    def do_GET(self):
        if self.path=='/status':
            self.send_response(200); self.send_header('Content-Type','application/json'); self.cors(); self.end_headers()
            r={'ok':LIBS_OK}
            if not LIBS_OK: r['error']=LIBS_ERR
            self.wfile.write(json.dumps(r).encode())
        elif self.path in ('/', '/app', '/app.html', '/index.html'):
            html=_get_html(); self.send_response(200); self.send_header('Content-Type','text/html; charset=utf-8'); self.cors(); self.end_headers()
            self.wfile.write(html.encode('utf-8'))

    def do_POST(self):
        length=int(self.headers.get('Content-Length',0)); body=self.rfile.read(length)
        try:
            payload=json.loads(body)
            # Endpoint dedicado para extraer fecha del ZIP (sin procesar nada mas)
            if self.path == '/fecha':
                zip_b64 = payload.get('zip','')
                fecha = extraer_fecha_zip(base64.b64decode(zip_b64)) if zip_b64 else None
                self.send_response(200); self.send_header('Content-Type','application/json'); self.cors(); self.end_headers()
                self.wfile.write(json.dumps({'fecha': fecha}).encode())
                return
            result=self.procesar(payload)
            self.send_response(200); self.send_header('Content-Type','application/json'); self.cors(); self.end_headers()
            self.wfile.write(json.dumps(result).encode())
        except Exception as e:
            import traceback
            tb = traceback.format_exc()
            print("\n=== ERROR ===")
            print(tb)
            print("=============\n")
            self.send_response(500); self.send_header('Content-Type','application/json'); self.cors(); self.end_headers()
            self.wfile.write(json.dumps({'error':str(e),'detalle':tb}).encode())
    def procesar(self,payload):
        if not LIBS_OK: raise Exception(f'Falta libreria: {LIBS_ERR}. Ejecuta ARRANCAR.bat.')
        config=payload['config']; grupos=payload['grupos']
        records=leer_dbf(base64.b64decode(payload['dbf']))
        polys=leer_shp(base64.b64decode(payload['shp']))
        cl=col_lote(records)
        b3,b4,b8,geo=leer_zip(base64.b64decode(payload['zip']))
        print(f"DEBUG leer_zip retorno: b3={b3 is not None}, b4={b4 is not None}, b8={b8 is not None}, geo={geo}")
        if geo is None:
            raise Exception("geo es None despues de leer_zip - el ZIP no pudo ser leido correctamente")
        olon,olat,plon,plat=geo
        print(f"DEBUG geo: olon={olon:.6f}, olat={olat:.6f}, plon={plon:.8f}, plat={plat:.8f}")
        print(f"DEBUG imagen shape: {b8.shape}, bbox lat=[{olat-b8.shape[0]*plat:.4f}, {olat:.4f}], lon=[{olon:.4f}, {olon+b8.shape[1]*plon:.4f}]")
        indices=calc_idx(b3,b4,b8,config['indice'])
        idx_nom='GNDVI' if config['indice']=='gndvi' else 'NDVI' if config['indice']=='ndvi' else 'GNDVI'
        img=indices.get('GNDVI',indices.get('NDVI'))
        print(f"DEBUG indices keys: {list(indices.keys())}, img is None: {img is None}")
        if img is None:
            raise Exception(f"No se pudo calcular el indice {config['indice']}. Verificá que las bandas correctas esten en el ZIP.")
        lotes_res=[]
        for grupo in grupos:
            pts=[]
            for pt in grupo['puntos']:
                try:
                    lat_v = float(pt['lat'])
                    lon_v = float(pt['lon'])
                    rinde_v = float(pt['rinde'])
                except (TypeError, ValueError):
                    print(f"Punto ignorado (valor invalido): {pt}")
                    continue
                import math
                if math.isnan(lat_v) or math.isnan(lon_v) or math.isnan(rinde_v):
                    print(f"Punto ignorado (NaN): amb={pt['amb']}")
                    continue
                print(f"Punto: {pt['amb']} lat={lat_v} lon={lon_v} rinde={rinde_v}")
                v=val_punto(img, lat_v, lon_v, olat, olon, plat, plon)
                print(f"  -> val_punto={v}")
                if v is not None:
                    pts.append({'amb':pt['amb'],'lat':lat_v,'lon':lon_v,'rinde':rinde_v,'idx_val':v})
            if len(pts)<2: raise Exception(f'El grupo "{grupo["nombre"]}" necesita al menos 2 puntos validos en la imagen.')
            xg=np.array([p['idx_val'] for p in pts]); yg=np.array([p['rinde'] for p in pts])
            sl,it,r,_,_=stats.linregress(xg,yg); r2=r**2
            for lote in grupo['lotes']:
                poly=buscar_poly(lote['nombre'],records,polys,cl)
                if poly is None:
                    disp=list(set(rec.get(cl,'') for rec in records if rec.get(cl,'')))
                    raise Exception(f'Lote "{lote["nombre"]}" no encontrado.\nColumna: "{cl}".\nDisponibles: {disp[:25]}')
                ha_manual = float(lote.get('sup_ha', 0) or 0)
                ha = ha_manual if ha_manual > 0 else area_ha(poly)
                prom,_=val_lote(img,poly,olat,olon,plat,plon)
                if prom is None: raise Exception(f'Sin pixeles validos en lote "{lote["nombre"]}".')
                rinde_kgha = sl*prom+it
                # rinde_est se guarda SIEMPRE en kg/ha (unidad interna).
                # La conversion a la unidad elegida por el usuario se hace solo al mostrar.
                ec=f"y = {sl:.2f} x {idx_nom} + ({it:.2f})"  
                # Solo mostrar en el mapa los puntos que caen dentro de este lote
                # (al mapa se le pasan los rindes ya convertidos para los rotulos)
                pts_en_lote = [(p['amb'],p['lat'],p['lon'],convertir_rinde(p['rinde'],config['unidad']))
                               for p in pts if pip(p['lon'], p['lat'], poly)]
                mb=gen_mapa(img,poly,pts_en_lote,olat,olon,plat,plon,
                            f"{idx_nom} - {lote['nombre']}",idx_nom,config['unidad'])
                lotes_res.append({'nombre':lote['nombre'],'campo':lote['campo'],'cultivo':lote['cultivo'],
                                  'variedad':grupo.get('variedad',''),'grupo_nombre':grupo['nombre'],
                                  'area_ha':ha,'idx_prom':prom,'r2':r2,'rinde_est':rinde_kgha,'ecuacion':ec,
                                  'puntos_datos':pts,'mapa_buf':mb})
        with tempfile.NamedTemporaryFile(suffix='.pdf',delete=False) as tmp: pdf_path=tmp.name
        gen_pdf(lotes_res,config,pdf_path)
        with open(pdf_path,'rb') as f: b64=base64.b64encode(f.read()).decode()
        os.unlink(pdf_path)
        # ── Generar PPTX con python-pptx ─────────────────────
        import base64 as _b64_2
        pptx_b64 = ''
        try:
            pptx_tmp = pdf_path.replace('.pdf', '.pptx')
            gen_pptx_python(lotes_res, config, pptx_tmp)
            with open(pptx_tmp, 'rb') as f2:
                pptx_b64 = _b64_2.b64encode(f2.read()).decode()
            os.unlink(pptx_tmp)
        except Exception as epptx:
            print(f"PPTX error: {epptx}")

        return {'ok':True,'pdf':b64,'pptx':pptx_b64}

if __name__=='__main__':
    print(f'Servidor iniciando en puerto {PORT}')
    socketserver.TCPServer.allow_reuse_address = True
    with socketserver.TCPServer(('0.0.0.0', PORT), Handler) as srv:
        srv.serve_forever()
